// 3점 평가 입력 검증
// score: 1(나쁨) | 2(보통) | 3(좋음)
// rationale: 근거 한 줄
// decision_ref: 평가 대상 결정 ID
// actor: 평가 대상 RA 에이전트 ID
const input = $input.item.json;

const score = parseInt(input.score);
if (![1, 2, 3].includes(score)) {
  throw new Error('score must be 1, 2, or 3. Got: ' + input.score);
}

const validActors = ['ra_us', 'ra_eu', 'ra_kr', 'op_manager', 'n8n_manager', 'infra_t3610', 'infra_gx10', 'infra_rpi'];
if (!validActors.includes(input.actor)) {
  throw new Error('Unknown actor: ' + input.actor);
}

return [{
  json: {
    score,
    rationale: (input.rationale || '').slice(0, 200),
    decision_ref: input.decision_ref || null,
    actor: input.actor,
    evaluated_by: 'human',
    evaluated_at: new Date().toISOString()
  }
}];

