// 가중치 반영 연결 자리 [IF]
// 평가된 사안 영역별 가중치 조정 연결점
// 조정 공식은 비워둠 — 학습이 정함
// weight-adjustment-config.json에서 읽음
const fs = require('fs');
let config = {};
try {
  config = JSON.parse(fs.readFileSync('/data/feedback/weight-adjustment-config.json', 'utf8'));
} catch {
  config = { adjustment_formula: null, neutral_on_no_score: true };
}

const feedback = $node['평가 입력 검증'].json;

// 조정 공식이 비어 있으면 기록만 하고 패스
if (!config.adjustment_formula) {
  return [{
    json: {
      _weight_adjustment: 'skipped_formula_empty',
      feedback_recorded: true,
      score: feedback.score,
      actor: feedback.actor
    }
  }];
}

// 공식이 채워지면 여기서 가중치 조정 로직 실행 (운영·학습이 채움)
// 현재는 interface만 존재 — 내부 구현 없음
return [{
  json: {
    _weight_adjustment: 'formula_not_implemented',
    feedback_recorded: true,
    score: feedback.score,
    actor: feedback.actor
  }
}];
